	if Eggs then
		local t2 = {}
		for i, v in ipairs(Eggs:GetDescendants()) do
			if v:IsA("MeshPart") or (v:IsA("SpecialMesh") or (v:IsA("Texture") or v:IsA("Decal"))) then
				table.insert(t2, v)
			end
		end
		if #t2 > 0 then
