			print("[AssetPreloader] Eggs preloaded:", #t2, "assets")
		end
	end
	local Items = ReplicatedStorage:WaitForChild("Items", 10)
	if Items then
		table.insert(t, Items)
		for i, v in ipairs(Items:GetDescendants()) do
			if v:IsA("MeshPart") or (v:IsA("Texture") or (v:IsA("Decal") or v:IsA("Sound"))) then
				table.insert(t, v)
			end
		end
	end
	local Blocks = ReplicatedStorage:WaitForChild("Blocks", 10)
	if Blocks then
		table.insert(t, Blocks)
		for i, v in ipairs(Blocks:GetDescendants()) do
			if v:IsA("MeshPart") or (v:IsA("Texture") or (v:IsA("Decal") or v:IsA("Sound"))) then
				table.insert(t, v)
			end
		end
	end
	local PlayerGui = Players.LocalPlayer:WaitForChild("PlayerGui")
	if PlayerGui then
		for i, v in ipairs(PlayerGui:GetDescendants()) do
			if v:IsA("ImageLabel") or v:IsA("ImageButton") then
				table.insert(t, v)
			end
		end
	end
	task.spawn(function() --[[ Line: 66 | Upvalues: t (copy), ContentProvider (ref), v1 (copy) ]]
		local UserInputService = game:GetService("UserInputService")
		if UserInputService.TouchEnabled and not UserInputService.KeyboardEnabled then
			for i = 1, #t, 50 do
				local t2 = {}
				for j = i, math.min(i + 50 - 1, #t) do
					table.insert(t2, t[j])
				end
				ContentProvider:PreloadAsync(t2)
				task.wait(0.1)
			end
		else
			ContentProvider:PreloadAsync(t)
		end
		print(string.format("[AssetPreloader] Finished loading %d assets in %.2f seconds.", #t, tick() - v1))
	end)
end)()

