-- ReplicatedStorage.Modules.LevelConfigurations
--
local t = {
	MaxLevel = 60,
	MaxBuyableLevel = 50,
	IncomeIncreasePerLevel = 0.5,
	SizeIncreasePerLevel = 0.03,
	RarityMultipliers = {
		Common = 1,
		Uncommon = 2,
		Rare = 4,
		Epic = 8,
		Legendary = 16,
		Mythical = 32,
		Secret = 64,
		Limited = 16,
		Normal = 1,
		["?"] = 1
	},
	GetTrainingTime = function(p1, p2) --[[ GetTrainingTime | Line: 28 ]]
		return math.clamp(math.floor(1.12 ^ (p1 - 1) * 60 * (({
			Common = 1,
			Rare = 1.3,
			Epic = 1.6,
			Legendary = 2,
			Mythical = 2.5,
			Secret = 3
		})[p2] or 1)), 30, 21600)
	end,
	BaseUpgradePrices = {}
}
for i = 1, t.MaxLevel - 1 do
	t.BaseUpgradePrices[i] = math.floor(math.pow(1.45, i - 1) * 100)
end
function t.GetUpgradePrice(p1, p2) --[[ GetUpgradePrice | Line: 65 | Upvalues: t (copy) ]]
	if t.MaxBuyableLevel <= p1 or t.MaxLevel <= p1 then
		return nil
	else
		local v2 = (t.BaseUpgradePrices[p1] or t.BaseUpgradePrices[#t.BaseUpgradePrices]) * (t.RarityMultipliers[p2] or 1)
		if v2 > 1000000 then
			return math.floor(v2 / 10000 + 0.5) * 10000
		else
			if v2 > 1000 then
				v2 = math.floor(v2 / 10 + 0.5) * 10
			end
			return v2
		end
	end
end
function t.GetIncomeMultiplier(p1) --[[ GetIncomeMultiplier | Line: 87 | Upvalues: t (copy) ]]
	return 1 + (math.max(p1 or 1, 1) - 1) * t.IncomeIncreasePerLevel
end
function t.GetSizeMultiplier(p1) --[[ GetSizeMultiplier | Line: 92 | Upvalues: t (copy) ]]
	local v1 = math.max(p1 or 1, 1)
	if v1 <= 100 then
		return 1 + (v1 - 1) * t.SizeIncreasePerLevel
	else
		return 1 + 99 * t.SizeIncreasePerLevel + (v1 - 100) * 0.005
	end
end
return t

