local Players = game:GetService("Players")
local LocalPlayer = Players.LocalPlayer
local v1 = script.Parent
local function updateFriendBoost() --[[ updateFriendBoost | Line: 5 | Upvalues: Players (copy), LocalPlayer (copy), v1 (copy) ]]
	local count = 0
	for i, v in ipairs(Players:GetPlayers()) do
		if v ~= LocalPlayer and LocalPlayer:IsFriendsWith(v.UserId) then
			count = count + 1
		end
	end
	v1.Text = "Friend Boost +" .. count * 10 .. "%"
	v1.TextColor3 = Color3.fromRGB(255, 255, 255)
end
